const webhookData = $('Webhook receptor Evolution API').first().json;
const dbResult = $input.first().json;

if (!dbResult || !dbResult.cliente_id) {
  return [{ json: { valido: false, razon: 'cliente_no_encontrado' } }];
}

const headerSecret = webhookData.headers?.['x-webhook-secret'] ||
                     webhookData.headers?.['x-api-key'] || '';

if (headerSecret !== dbResult.webhook_secret) {
  return [{ json: { valido: false, razon: 'secreto_invalido' } }];
}

return [{
  json: {
    valido: true,
    cliente_id: dbResult.cliente_id,
    nombre: dbResult.nombre,
    ecommerce_tipo: dbResult.ecommerce_tipo,
    ecommerce_url: dbResult.ecommerce_url,
    n8n_credential_name: dbResult.n8n_credential_name,
    cloudinary_folder: dbResult.cloudinary_folder,
    whatsapp_instance: dbResult.whatsapp_instance
  }
}];

const clienteData = $('Validar secreto del webhook y cliente activo').first().json;
const webhookBody = $('Webhook receptor Evolution API').first().json.body;

const remoteJid = webhookBody.data?.key?.remoteJid || '';
const telefono = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');

return [{
  json: {
    ...clienteData,
    telefono,
    push_name: webhookBody.data?.pushName || null,
    message_type: webhookBody.data?.messageType,
    message_id: webhookBody.data?.key?.id,
    server_url: webhookBody.data?.serverUrl || '',
    raw_message: webhookBody.data?.message || {}
  }
}];

const extractorData = $('Extraer número de teléfono del remitente').first().json;
const usuarioData = $input.first().json;
const msgType = extractorData.message_type || '';

const TIPOS_TEXTO = ['conversation', 'extendedTextMessage'];
const TIPOS_IMAGEN = ['imageMessage'];
const TIPOS_NO_SOPORTADOS = ['audioMessage', 'documentMessage', 'videoMessage', 'locationMessage'];
const TIPOS_IGNORAR = ['stickerMessage', 'reactionMessage', 'contactMessage', 'contactsArrayMessage'];

let categoria;
if (TIPOS_TEXTO.includes(msgType)) categoria = 'texto';
else if (TIPOS_IMAGEN.includes(msgType)) categoria = 'imagen';
else if (TIPOS_NO_SOPORTADOS.includes(msgType)) categoria = 'no_soportado';
else categoria = 'ignorar';

return [{
  json: {
    ...extractorData,
    usuario_nombre: usuarioData.nombre,
    rol: usuarioData.rol,
    categoria_mensaje: categoria,
    message_type_original: msgType
  }
}];

const categoriaData = $input.first().json;
const rawMessage = categoriaData.raw_message || {};

const texto = rawMessage.conversation ||
              rawMessage.extendedTextMessage?.text ||
              rawMessage.imageMessage?.caption || '';

const textoLimpio = texto.replace(/<[^>]+>/g, '').trim();

return [{
  json: {
    ...categoriaData,
    mensaje_texto: textoLimpio,
    imagen_base64: null,
    imagen_mimetype: null
  }
}];

const imagenResp = $input.first().json;
const categoriaData = $('Categorizar tipo de mensaje entrante').first().json;
const caption = $('Webhook receptor Evolution API').first().json.body?.data?.message?.imageMessage?.caption || null;

const base64Raw = imagenResp.base64 || '';
const base64Clean = base64Raw.replace(/^data:[^;]+;base64,/, '');

const tamanoBytes = (base64Clean.length * 3) / 4;
const limiteBytes = 5 * 1024 * 1024;

if (tamanoBytes > limiteBytes) {
  return [{
    json: {
      ...categoriaData,
      mensaje_texto: caption,
      imagen_base64: null,
      imagen_mimetype: null,
      imagen_error: 'La imagen supera el límite de 5MB. Por favor envía una imagen más pequeña.'
    }
  }];
}

return [{
  json: {
    ...categoriaData,
    mensaje_texto: caption,
    imagen_base64: base64Clean,
    imagen_mimetype: imagenResp.mimetype || 'image/jpeg',
    imagen_error: null
  }
}];

const errorData = $input.first().json;
return [{
  json: {
    workflow: 'WF-A_receptor',
    nodo: errorData.execution?.lastNodeExecuted || 'desconocido',
    telefono: null,
    error_tipo: 'ERROR_RECEPCION',
    error_detalle: errorData.error?.message || JSON.stringify(errorData.error || {})
  }
}];
